    cols = tl.arange(0, BLOCK_C)
    mask = cols < C
    a = tl.load(a_ptr + row * C + cols, mask=mask, other=0.0)
    tl.store(out_ptr + row, tl.sum(a.to(tl.float32), axis=0).to(a.dtype))


