def _k0(a):
    return a.contiguous()


def _k1(a: torch.Tensor, _dims=[-1], _keepdim=True) -> torch.Tensor:
    if HAS_TRITON and a.ndim == 2:
        R, C = a.shape
        dims_norm = [d % a.ndim for d in _dims]
